    ('MUS-F 530', 'FOUNDATIONS IN LATIN AMERICAN AND CARIBBEAN PERCUSSION', '10966', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'MA 401', 'Andy Miller', 0, NULL, 'Lecture', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Hands-on percussion course focusing on folkloric percussion throughout Latin America and the Caribbean. These may include music traditions from Cuba, Puerto Rico, the Dominican Republic, Haiti, Trinidad and Tobago, Mexico, Guatemala, Belize, Venezuela, Colombia, Peru, and Brazil.', ARRAY[]::TEXT[], NULL),
    ('MUS-F 531', 'GRADUATE EAR TRAINING FOR CONDUCTORS', '9066', 'Closed', 'MF Monday, Friday 8:00 AM–8:50 AM', 'SM 005', 'Dominick DiOrio', 0, NULL, 'Lecture', '1', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Study and performance of complex pitch and rhythmic combinations. Development of the ear and its application to the process of sight reading, especially as relates to score study and rehearsal for conductors. Emphasis on ability to "hear" scores through audiation. Students will sing choral scores at sight and refine intonation.', ARRAY[]::TEXT[], NULL),
    ('MUS-F 540', 'POSTURAL ALIGNMENT FOR THE MUSICIAN I', '3493', 'Closed', 'TuTh Tuesday, Thursday 10:25 AM–11:15 AM', 'SM C113', 'Jonathan Conjurske', 0, NULL, 'Lecture', '1', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Biomechanical integration of the muscular and skeletal systems to promote a balanced and supported posture for all musical activities. Centering and relaxation skills.', ARRAY[]::TEXT[], NULL),
