    ('MUS-F 590', 'TECHNIQUES IN MARCHING BAND FOR GRADUATE STUDENTS', '2296', 'Class Status', 'TuTh Tuesday, Thursday 10:25 AM–11:15 AM', 'MC 066', 'Tiffany Galus', 5, NULL, 'Lecture', '3', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], 'Overview of the complete marching band program (college and high school) including show planning, drill writing, administration, and rehearsal techniques.', ARRAY[]::TEXT[], NULL),
    ('MUS-F 603', 'SEMINAR IN PERCUSSION PERFORMANCE I', '2297', 'Class Status', NULL, NULL, 'John Tafoya', 2, NULL, 'Seminar', '2', NULL, ARRAY[]::TEXT[], 'The technical and physical factors governing the performance of solo, chamber, and orchestral literature.', ARRAY[]::TEXT[], NULL),
    ('MUS-F 650', 'COACHING CHAMBER MUSIC', '7495', 'Class Status', 'W Wednesday 4:20 PM–6:20 PM', 'JS 315', 'Eli Eban', 9, NULL, 'Lecture', '1', 'EAST STUDIO BUILDING', ARRAY[]::TEXT[], 'For doctoral students meeting coaching requirements for chamber ensembles.', ARRAY[]::TEXT[], NULL),
    ('MUS-F 650', 'COACHING CHAMBER MUSIC', '13140', 'Class Status', NULL, NULL, 'Joseph Gramley', 1, NULL, 'Lecture', '1', 'EAST STUDIO BUILDING', ARRAY[]::TEXT[], 'For doctoral students meeting coaching requirements for chamber ensembles.', ARRAY[]::TEXT[], NULL),
    ('MUS-G 370', 'TECHNIQUES FOR CONDUCTING', '2299', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 11:35 AM–12:25 PM', 'MA 405', 'Gabriel Fanelli, Dominick DiOrio', 1, NULL, 'Lecture', '2', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Introduction to philosophy and fundamentals of conducting. Scores preparation, baton and hand gestures for the right hand and use of the left hand; all standard meters and time patters; varying dynamics, accents, musical characteristics and styles.', ARRAY[]::TEXT[], NULL),
    ('MUS-G 370', 'TECHNIQUES FOR CONDUCTING', '3720', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 11:35 AM–12:25 PM', 'MC 066', 'Eric Smedley', 4, NULL, 'Lecture', '2', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Introduction to philosophy and fundamentals of conducting. Scores preparation, baton and hand gestures for the right hand and use of the left hand; all standard meters and time patters; varying dynamics, accents, musical characteristics and styles.', ARRAY[]::TEXT[], NULL),
    ('MUS-G 370', 'TECHNIQUES FOR CONDUCTING', '2298', 'Closed', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 8:00 AM–8:50 AM', 'MA 405', 'Benjamin Wegner, Dominick DiOrio', 0, NULL, 'Lecture', '2', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Introduction to philosophy and fundamentals of conducting. Scores preparation, baton and hand gestures for the right hand and use of the left hand; all standard meters and time patters; varying dynamics, accents, musical characteristics and styles.', ARRAY[]::TEXT[], NULL),
    ('MUS-G 373', 'INSTRUMENTAL CONDUCTING', '2300', 'Class Status', 'TuTh Tuesday, Thursday 10:25 AM–12:25 PM', 'MA 452', 'Jason Nam', 1, NULL, 'Lecture', '2', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Further development of score reading and conducting techniques. Emphasis on experience conducting live instrumental ensembles.', ARRAY[]::TEXT[], NULL),
    ('MUS-G 374', 'ADVANCED INSTRUMENTAL CONDUCTING', '6465', 'Class Status', 'TuTh Tuesday, Thursday 10:25 AM–12:20 PM', 'MC 070', 'Eric Smedley', 5, NULL, 'Lecture', '2', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], 'Refinement of conducting techniques through work on advanced repertoire and score study, score interpretation, and rehearsal technqiues.', ARRAY[]::TEXT[], NULL),
    ('MUS-G 504', 'MASTER''S CHORAL CONDUCTING PRACTICUM', '5249', 'Class Status', NULL, NULL, 'Betsy Burleigh, Dominick DiOrio', 4, NULL, 'Practicum', '0', NULL, ARRAY[]::TEXT[], 'Supervised work with a choral ensemble, including public performance of approximately 10 minutes.', ARRAY[]::TEXT[], NULL),
    ('MUS-G 535', 'MASTER''S CHORAL CONDUCTING: RENAISSANCE TO 1700', '30302', 'Class Status', 'MF Monday, Friday 9:10 AM–11:10 AM', 'MA 405', 'Chris Albanese, Carolann Buff', 6, NULL, 'Lecture', '2', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Study and development of effective gesture and stylistically appropriate interpretations based on score and era. Will include chironomy, chant, choral repertoire of the Renaissance, and the music of the early Baroque including compositions by Monteverdi and Schütz.', ARRAY[]::TEXT[], NULL),
    ('MUS-G 555', 'FOUNDATIONS IN CHORAL CONDUCTING', '2301', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 10:25 AM–11:15 AM', 'MA 404', 'Betsy Burleigh', 6, NULL, 'Lecture', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Techniques for the beginning choral conductor, including fundamentals of baton technique, rehearsal skills, choral sound development, and score preparation. May serve as a prerequisite for G560 Graduate Choral Conducting. Does not satisfy degree requirements for graduate choral conducting majors. May be used toward a doctoral minor in choral conducting.', ARRAY[]::TEXT[], NULL),
    ('MUS-G 560', 'GRADUATE CHORAL CONDUCTING', '2302', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 10:25 AM–11:15 AM', 'MA 404', 'Betsy Burleigh', 6, NULL, 'Lecture', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'Study and development of effective gesture and stylistically appropriate interpretations of repertoire from a variety of time periods. For students majoring in fields other than choral conducting.', ARRAY[]::TEXT[], NULL),
    ('MUS-G 566', 'INTERPRETATION AND CONDUCTING OF BAND LITERATURE', '10856', 'Class Status', 'TuTh Tuesday, Thursday 10:25 AM–12:20 PM', 'MC 070', 'Eric Smedley', 5, NULL, 'Lecture', '3', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], 'Study of concert band literature with emphasis on original band compositions. Rehearsal techniques and conducting problems.', ARRAY[]::TEXT[], NULL),
    ('MUS-G 567', 'INTERPRETATION AND CONDUCTING OF BAND LITERATURE II', '11127', 'Class Status', 'TuTh Tuesday, Thursday 10:25 AM–12:20 PM', 'MC 070', 'Eric Smedley', 5, NULL, 'Lecture', '3', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], 'Study of selected wind literature at the most advanced levels for both small and large ensembles. Continued development of baton and rehearsal techniques and score preparation. Rehearsal and performance of selected works is included.', ARRAY[]::TEXT[], NULL),
