    ('MUS-J 208', 'CONDITIONING THE BALLET BODY', '9045', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–11:40 AM', 'MC 305', 'Rebecca Janes, Sarah Wroth, Alyssa McPherson', 39, NULL, 'Lecture', '1', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], 'Injury prevention is an important part of ballet education. Principles of physical therapy, Pilates, and basic floor exercises will be used to train muscles to be strong enough to support all ballet work and supple enough to move freely with as little tension as possible.', ARRAY[]::TEXT[], NULL),
    ('MUS-J 208', 'CONDITIONING THE BALLET BODY', '8644', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–11:40 AM', 'MC 305', 'Rebecca Janes, Sarah Wroth, Alyssa McPherson', 0, NULL, 'Lecture', '1', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], 'Injury prevention is an important part of ballet education. Principles of physical therapy, Pilates, and basic floor exercises will be used to train muscles to be strong enough to support all ballet work and supple enough to move freely with as little tension as possible.', ARRAY[]::TEXT[], NULL),
    ('MUS-J 220', 'CONTEMPORARY BALLET', '10305', 'Class Status', 'TuThF Tuesday, Thursday, Friday 9:35 AM–11:05 AM', 'MC 305', 'Robin Allen, Sarah Wroth', 25, NULL, 'Activity', '1', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], 'Study of contemporary ballet movement. Students will work towards the coordination of full body use as applied to musical expression. Contemporary repertoire will be taught and refined and students will gain confidence in this genre. Students will be able to apply their contemporary corrections to all their classical ballet practices.', ARRAY[]::TEXT[], NULL),
    ('MUS-J 220', 'CONTEMPORARY BALLET', '12613', 'Class Status', 'F Friday 10:05 AM–11:20 AM', 'MC 305', 'Rebecca Janes, Sarah Wroth', 14, NULL, 'Activity', '1', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], 'Study of contemporary ballet movement. Students will work towards the coordination of full body use as applied to musical expression. Contemporary repertoire will be taught and refined and students will gain confidence in this genre. Students will be able to apply their contemporary corrections to all their classical ballet practices.', ARRAY[]::TEXT[], NULL),
