    ('MUS-K 340', 'SONGWRITING FOR MUSIC PRODUCTION', '12651', 'Closed', 'MWF Monday, Wednesday, Friday 4:20 PM–5:10 PM', 'SM C018', 'Michael Stucker, Adele Fournet', 0, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Students will learn songwriting by studying melody, harmony, tempo, structure, and key. Pop, R&B, country, jazz, and world musical genres will be included. Songwriting methodology will be demonstrated by the instructor and through masterclasses from successful music artists. Restricted to music majors and students pursuing the music production minor.', ARRAY[]::TEXT[], NULL),
    ('MUS-K 361', 'INTRODUCTION TO MIDI AND COMPUTER MUSIC', '6275', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'SM 373', 'Chi Wang', 1, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Modest working knowledge of personal computers. Basics of the Music Instrument Digital Interface system, it''s software, and the instruments commonly used with desktop MIDI workstations (synthesizers, digital samplers). MIDI sequencing, digital audio editing, and principles of digital synthesis. The course is intended for those with little prior technical training.', ARRAY[]::TEXT[], NULL),
