    ('MUS-M 368', 'BALLET HISTORY', '8671', 'Class Status', 'MW Monday, Wednesday 10:25 AM–11:15 AM', 'MA 452', 'Sarah Wroth', 16, NULL, 'Lecture', '2', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'This course teaches the principles of creativity, experimentation, and collaboration on which ballet as an art form was built. Students will study the chronology of ballet''s evolution as well as the major choreographers, composers, and organizational leaders who created its established forms and expressive tools.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 390', 'HISTORY OF JAZZ 1: ORIGINS TO 1959', '10209', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'MA 404', 'Natalie Boeyink', 7, NULL, 'Lecture', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'The history of jazz from origins to 1959 explored through selected recordings and readings. The course will focus on selected artists and styles discussed in the context of American history.', ARRAY[]::TEXT[], NULL),
