    ('MUS-M 519', 'BAROQUE PERFORMANCE PRACTICE', '15033', 'Class Status', 'WF Wednesday, Friday 10:25 AM–11:15 AM', 'MU 205', 'Dana Marsh', 5, NULL, 'Lecture', '2', 'MERRILL HALL', ARRAY[]::TEXT[], 'The basic literature of the Baroque period with performance-oriented analysis, survey of original sources, and study of performance-related theoretical works.', ARRAY[]::TEXT[], NULL),
    ('MUS-M 523', 'MUSIC AND RHETORIC IN PERFORMANCE', '9465', 'Class Status', 'TuTh Tuesday, Thursday 10:25 AM–11:15 AM', 'MU 204', 'Dana Marsh', 2, NULL, 'Lecture', '2', 'MERRILL HALL', ARRAY[]::TEXT[], 'This course deals with changing relationships between words and music (c.1300-1750) through the evidence of contemporaneous ideologies applied to composition, interpretation and performance. Beginning with classical authors who prescribe techniques for persuasive oration, the reception of such principles within both the Renaissance and Baroque periods will be given central emphasis.', ARRAY[]::TEXT[], NULL),
